+fn bench_strcasestr_absent(c: &mut Criterion) {
+    let sizes: &[usize] = &[16, 64, 256, 1024, 4096];
+    let mode = mode_label();
+    let needle = b"zq\0";
+    let mut group = c.benchmark_group("strcasestr_absent");
